#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Check for stale sensor data timeout (>1000ms since last valid sensor frame) */
    if (!controller->has_valid_sensor || (input.now_ms - controller->last_valid_sensor_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        controller_set_safe_off(controller);
        output.timed_out = true;
    }
    else if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        /* Valid temperature received */
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        bool heater_should_turn_on = (controller->last_temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD);
        bool heater_should_turn_off = (controller->last_temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD);
        bool is_in_holding_zone = (controller->last_temperature_c >= CONTROLLER_TEMP_LOW_THRESHOLD && controller->last_temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD);
        bool is_near_upper_band = (controller->last_temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && controller->last_temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD);

        /* Check if temperature is rising compared to previous valid sample */
        bool temp_is_rising = false;
        if (controller->has_valid_sensor && controller->last_temperature_c > 0) {
            temp_is_rising = (input.temperature_c > controller->last_temperature_c);
        }

        /* Control policy logic:
         * - TEMP < 47: turn heater ON (state HEATING)
         * - TEMP > 52: turn heater OFF (state SAFE_OFF)
         * - 47 <= TEMP < 50: hold previous safe actuator state (state HOLDING)
         * - 50 <= TEMP <= 52:
         *   - If rising temp: turn heater OFF early, treat as HOLDING (not SAFE_OFF)
         *   - If not rising: hold previous safe actuator state (state HOLDING)
         */

        if (heater_should_turn_on && !is_near_upper_band) {
            /* Heating zone: TEMP < 47 */
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        }
        else if (heater_should_turn_off) {
            /* Above upper band: TEMP > 52 */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_SAFE_OFF;
        }
        else if (is_in_holding_zone) {
            /* Inside holding zone: 47 <= TEMP < 50 */
            /* Hold previous safe actuator state - always SAFE_OFF in this zone */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        }
        else if (is_near_upper_band) {
            /* Near upper band: 50 <= TEMP <= 52 */
            if (temp_is_rising) {
                /* Rising temperature - turn heater off early, treat as HOLDING */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            }
            else {
                /* Not rising - hold previous safe actuator state */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        }
        else {
            /* Fallback to SAFE_OFF for any other case */
            controller_set_safe_off(controller);
        }
    }
    else if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT || input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        /* Malformed input or sensor timeout - fail safe */
        controller_set_safe_off(controller);
    }
    else {
        /* No input - keep current state or go to SAFE_OFF */
        if (!controller->has_valid_sensor && controller->state != CONTROLLER_STATE_HEATING) {
            controller_set_safe_off(controller);
        }
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

